  const [activeTab, setActiveTab] = useState('overview');
  const [activeSection, setActiveSection] = useState('dashboard');

  // Get active tab from URL or state
  useEffect(() => {
    const pathSegments = location.pathname.split('/');
    const currentSection = pathSegments[1] || 'dashboard';
    const currentTab = pathSegments[2] || 'overview';
    setActiveSection(currentSection);
    setActiveTab(currentTab);
  }, [location]);

  const mainNavigation = [
    { name: 'Back to Site', href: '/', icon: ArrowLeft, external: true },
    { 
      name: 'Dashboard', 
      section: 'dashboard',
      icon: Home,
      description: 'Overview & Analytics',
      tabs: [
        { name: 'Overview', tab: 'overview', href: '/dashboard' },
        { name: 'Analytics', tab: 'analytics', href: '/dashboard/analytics' },
        { name: 'Activity', tab: 'activity', href: '/dashboard/activity' }
