        return <CustomerDashboard />;
      case 'vendor':
        return <VendorDashboard />;
      case 'admin':
        return <AdminDashboard />;
      default:
        return <CustomerDashboard />;
    }
  };

  // Get tab content based on active tab
  const getTabContent = () => {
    switch (activeTab) {
      case 'profile':
        return <ProfileTab />;
      case 'referrals':
        return <ReferralTab />;
      case 'settings':
        return <div className="text-center py-12 text-gray-500">Settings page coming soon...</div>;
      default:
        return getDashboardContent();
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-16">
      <div className="flex">
        {/* Sidebar */}
        <div className="w-64 bg-white shadow-lg min-h-screen">
          <div className="p-6">
            <a href="/" className="block mb-6">
              <h1 className="text-xl font-bold text-gray-900 hover:text-orange-600 transition-colors">Swift Fix Pro</h1>
            </a>

            <nav className="space-y-2">
              {navigation.map((item) => {
                const isActive = item.tab === activeTab;

                if (item.external) {
                  return (
                    <a
                      key={item.name}
                      href={item.href}
                      className="flex items-center px-4 py-2 rounded-lg transition-colors text-gray-600 hover:bg-gray-100"
                    >
                      <item.icon size={20} className="mr-3" />
                      {item.name}
                    </a>
                  );
                }

                return (
                  <Link
                    key={item.name}
                    to={item.href}
                    onClick={() => setActiveTab(item.tab)}
                    className={`flex items-center px-4 py-2 rounded-lg transition-colors ${
                      isActive
                        ? 'bg-orange-100 text-orange-700'
                        : 'text-gray-600 hover:bg-gray-100'
                    }`}
                  >
                    <item.icon size={20} className="mr-3" />
                    {item.name}
                  </Link>
                );
              })}
            </nav>

            <div className="mt-8 pt-6 border-t">
              <button
                onClick={handleLogout}
                className="flex items-center px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg w-full"
              >
                <LogOut size={20} className="mr-3" />
                Logout
              </button>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 p-8">
          <Routes>
            <Route path="/" element={getTabContent()} />
            <Route path="/profile" element={<ProfileTab />} />
            <Route path="/referrals" element={<ReferralTab />} />
            <Route path="/settings" element={<div className="text-center py-12 text-gray-500">Settings page coming soon...</div>} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;
